import boto3
import re

def is_valid_url(url):
    # Basic URL validation
    return re.match(r'^https://[^\s]+$', url) is not None

def create_sns_subscription():
    sns_client = boto3.client('sns')
    topic_arn = 'arn:aws:sns:your-region:your-account-id:your-topic-name'
    
    user_provided_url = input("Enter the subscription endpoint (HTTPS URL): ").strip()
    
    if not is_valid_url(user_provided_url):
        print("Invalid URL. Please provide a valid HTTPS URL.")
        return
    
    try:
        response = sns_client.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=user_provided_url
        )
        print(f"Subscription ARN: {response['SubscriptionArn']}")
    except Exception as e:
        print(f"An error occurred: {e}")

if __name__ == "__main__":
    create_sns_subscription()